import axios from 'axios';

const API_URL = 'http://localhost:8000/api';

const api = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

export const analyzeText = (data: { text: string; context?: string }) => {
  return api.post('/scam/analyze', data);
};

export const analyzeJob = (data: { job_text: string; company_name?: string }) => {
  return api.post('/jobs/analyze', data);
};

export const checkURL = (data: { url: string }) => {
  return api.post('/url/check', data);
};

export const analyzeImage = (file: File) => {
  const formData = new FormData();
  formData.append('image', file);
  return api.post('/image/analyze', formData, {
    headers: {
      'Content-Type': 'multipart/form-data',
    },
  });
};

export default api;
